### Custom Path Addition
```rust
/// Allow user to add paths not auto-detected
fn add_custom_paths_prompt(&mut self) -> Result<(), SetupError> {
    println\!("\n{}", "Common agent paths:".dimmed());
    println\!("  ~/.claude/projects       - Claude Code sessions");
    println\!("  ~/.codex/sessions        - OpenAI Codex sessions");
    println\!("  ~/.cursor                - Cursor editor sessions");
    println\!("  ~/.gemini/tmp            - Gemini CLI sessions\n");

    let input: String = dialoguer::Input::new()
        .with_prompt("Enter path to add (or blank to cancel)")
        .allow_empty(true)
        .interact_text()?;

    if input.is_empty() {
        return Ok(());
    }

    // Select which source to add path to
    let source_names: Vec<&str> = self.sources_to_add.iter().map(|s| s.name.as_str()).collect();
    let idx = dialoguer::Select::new()
        .with_prompt("Add path to which source?")
        .items(&source_names)
        .interact()?;

    self.sources_to_add[idx].paths.push(input);
    Ok(())
}
```

